starterCode.javascript:
// Define a middleware function to handle GET requests to the root URL
app.get('/', (req, res) => {
  res.send('Hello, Express!');
});

// Define a middleware function to handle POST requests to the root URL
app.post('/', (req, res) => {
  res.status(405).send('Method Not Allowed');
});

// Define a middleware function to handle GET requests to the /users URL
app.get('/users', (req, res) => {
  res.send('Users list');
});

